// Search for types that contain specimenID, aliquotID, and individualID
const specimenResult = tools.graph_search_nodes({
  expression: "specimenID",
  nodeType: "Type",
  includeRelations: true
});

const aliquotResult = tools.graph_search_nodes({
  expression: "aliquotID",
  nodeType: "Type",
  includeRelations: true
});

const individualResult = tools.graph_search_nodes({
  expression: "individualID",
  nodeType: "Type",
  includeRelations: true
});

// Extract type IDs from each search
const specimenTypes = specimenResult.nodes.map(n => n[0]);
const aliquotTypes = aliquotResult.nodes.map(n => n[0]);
const individualTypes = individualResult.nodes.map(n => n[0]);

// Find intersection - types that have all three fields
const intersection = specimenTypes.filter(id => 
  aliquotTypes.includes(id) && individualTypes.includes(id)
);

return {
  specimenTypes: specimenResult.nodes.map(n => [n[0], n[1]]),
  aliquotTypes: aliquotResult.nodes.map(n => [n[0], n[1]]),
  individualTypes: individualResult.nodes.map(n => [n[0], n[1]]),
  typesWithAllThree: intersection
};
